from pathlib import Path as FilePath

from pybrid.redac import REDAC
from pybrid.base.proto.io import ProtoIO
from pybrid.redac.protocol.serializer import REDACDeserializer

# Import a computer hardware structure from a previous export.
# This export was generated by running `pybrid redac extract --export redac-0.apb`
source = FilePath(__file__).parent / "redac-0.apb"
module = ProtoIO.load_module(str(source))
deserializer = REDACDeserializer()
computer = REDAC(entities=[
    deserializer.deserialize_specification(item.entity_specification.entity, None)
    for item in module.items
    if item.HasField("entity_specification")
])

# You can configure arbitrary parts of the computer offline
for carrier in computer.carriers:
    for cluster in carrier.clusters:
        # Configure harmonic oscillator
        cluster.route(0, 0, -1.0, 1)
        cluster.route(1, 1, 1.0, 0)
        cluster.m0block.elements[0].ic = 0.42
        # Configure which signals you want to capture
        computer.daq.capture(cluster.m0block.elements[0], cluster.m0block.elements[1])

# Export PB configuration for later use via `pybrid redac run -c sinusoidal-circuit.apb`
serializer = computer.get_serializer()()
module = serializer.serialize(computer)

target = FilePath(__file__).parent / "redac-0-configuration.apb"
ProtoIO.store_module(module, str(target))
